shape.script:
function getHandles(params) {
    return {
        n: [0, -params.size.y],
        s: [0, params.size.y],
        e: [params.size.x, 0],
        w: [-params.size.x, 0],
        ne: [params.size.x, -params.size.y],
        se: [params.size.x, params.size.y],
        nw: [-params.size.x, -params.size.y],
        sw: [-params.size.x, params.size.y]
    }
}

function getPath(params) {
    let width = params.size.x;
    let height = params.size.y;
    let cw = 0.551915024494 * width;
    let ch = 0.551915024494 * height;
    return [
        {
            in:[-cw,-height],
            p:[0,-height],
            out:[cw,-height],
        },
        {
            in:[width,-ch],
            p:[width,0],
            out:[width,ch]
        },
        {
            in:[cw,height],
            p:[0,height],
            out:[-cw,height]
        },
        {
            in:[-width,ch],
            p:[-width,0],
            out:[-width,-ch]
        },
        {closed:true}
    ];
}
